import json, os
with open('images.json') as f:
    data = json.load(f)

# Walk all image entries recursively
def find_images(obj, path=''):
    found = []
    if isinstance(obj, dict):
        src = obj.get('src', '')
        if src and src.startswith('/images/'):
            found.append(src)
        for k, v in obj.items():
            found.extend(find_images(v, f'{path}.{k}'))
    if isinstance(obj, list):
        for i, v in enumerate(obj):
            found.extend(find_images(v, f'{path}[{i}]'))
    return found

refs = set(find_images(data))
existing_webp = set()
existing_png = set()
for root, dirs, files in os.walk('public/images'):
    for f in files:
        path = f'/images/{os.path.relpath(os.path.join(root, f), \"public/images\")}'
        if f.endswith('.webp'):
            existing_webp.add(path)
        elif f.endswith('.png'):
            existing_png.add(path)

missing_webp = [r for r in refs if r.endswith('.webp') and r not in existing_webp]
