let imagesJson: any = null

export function resolveContent(content: any, key: string): any {
  if (!content || !key) return null
  let sc = content[key]
  if (!sc && key.includes('.')) sc = key.split('.').reduce((o: any, k: string) => o?.[k], content)
  return sc
}

export function loadImages(): any {
  if (!imagesJson) {
    try {
      const fs = require('fs')
      const path = require('path')
      const data = JSON.parse(fs.readFileSync(path.join(process.cwd(), 'images.json'), 'utf-8'))
      imagesJson = data.images || data
    } catch { imagesJson = {} }
  }
  return imagesJson
}

export function resolveImage(ref: string): string {
  if (!ref) return ''
  if (ref.startsWith('@img:')) {
    const key = ref.replace('@img:', '')
    const imgs = loadImages()
    const parts = key.split('.')
    let obj = imgs
    for (const p of parts) {
      if (obj?.[p]) obj = obj[p]
      else return ''
    }
    return obj?.src || obj?.fallbackSrc || ''
  }
  return ref
}
"}

